sys.setrecursionlimit(10**9)
def input(): return sys.stdin.readline().strip()


def dfs(i):
    global color
    for j in range(i+1,n):
        if a[i][j] == 0:
            continue
        if color[j] == -1:
            color[j] = 1-color[i]
            dfs(j)
        elif color[j] == color[i]:
            color[i] = 1-color[i]
            dfs(i)
            return


